+        assert_eq!(
+            AirtableClient::sanitize_path_segment("tblXYZ", "table_id").unwrap(),
+            "tblXYZ"
+        );
+        assert_eq!(
+            AirtableClient::sanitize_path_segment("recDEF456", "record_id").unwrap(),
+            "recDEF456"
+        );
+    }
